var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어때? 함선 신호 잡혀?","JPN":"どう？　艦船のシグナルは届いた？","ENG":"Okay, did you find the ship's signals?","TWN":"怎麼樣？有找到艦船訊號嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아직 먹통이야. 아무래도 우리만 조난당한 것 같아.","JPN":"まだダメ。どうやら私たちだけ遭難したみたい。","ENG":"Not yet. We might be the only ones who got stranded.","TWN":"還沒，很可能遇難的只有我們。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"이, 이상하네. 분명 다이브 할 때까지는 다른 사람들도 함께 있었는데, 침식체들이랑 싸우다 보니 어느 순간 모두 사라졌어.","JPN":"お、おかしいね。ダイブするまでは他の人たちも確かに一緒にいたのに、侵食体と戦ってる間にいなくなってたの。","ENG":"This makes no sense. All the others who dove with us disappeared while we were busy fighting C.O.s.","TWN":"奇…奇怪。明明躍入的時候，其他人都還在，但和侵蝕體交手後就突然消失不見？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"게다가 이 숲… 함선에서는 본적 없던 풍경이라고. 환경이 바뀌다니, 말이 안 되지 않아?","JPN":"それにこの森……艦船からは見たことない風景だな。環境が変わるなんてあり得ない話だ。","ENG":"Besides, this forest. I don't remember seeing it from the ship. But the environment can't have changed, can it?","TWN":"還有這片森林…我從未在艦船裡看過這種景象，環境竟然變了，不覺得很奇怪嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"애초에 이면세계잖아. 여기서 말이 되는 일만 기대하는 게 욕심일지도 모르지.","JPN":"そもそも裏世界でしょ。あり得るはずのことを期待する方が贅沢かもしれない。","ENG":"We're on the Counterside. Anything can happen here.","TWN":"我們不是在異界嗎？在異界哪有所謂的正常。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"린의 말이 맞아. 고심도에서는 충분히 일어날 수 있는 일이니까.","JPN":"リンの言うとおりね。高深度では十分に起こり得ることだから。","ENG":"Lin's right. Things like this can happen, especially in the hyperdepths.","TWN":"曉琳說的沒錯，在高深度確實有可能發生這種事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그러니 이럴 때일수록 당황하지 말고 정신 바짝 차려야 해. 할 수 있지?","JPN":"だからこういう時こそ、慌てずに気を引き締めていこう。いいね？","ENG":"So, we'd better stay sharp. Get it?","TWN":"所以越是在這種時候，越要保持冷靜，懂吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"으, 응! 대장만 믿을게!","JPN":"う、うん！　隊長を信じる！","ENG":"O-okay! I'm counting on you, Cap!","TWN":"嗯嗯！我相信隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"앗, TV다! 저 나무 위에 TV가 있어!","JPN":"あっ、テレビ！　あの木の上にテレビがあるぞ！","ENG":"Ah, a TV! There's a TV on the tree over there!","TWN":"是電視！那個樹上有電視！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"뭐래? 이런 곳에 TV 같은 게 있을 리가…","JPN":"はあ？　こんな所にテレビなんかあるわけ……","ENG":"What are you talking about? What TV in a place like—","TWN":"胡說什麼！樹上怎麼可能有電視…"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>평온한 밤입니다, 여러분!</color>","JPN":"<color=#ffd34c>こんばんは、皆様！</color>","ENG":"<color=#ffd34c>It's a peaceful night, everyone.</color>","TWN":"<color=#ffd34c>哈囉～大家晚安！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L16_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>곧 정신없는 난장판이 펼쳐지겠지만, 적어도 지금은 이 숲의 고요함을 즐기며 이야길 나눌 수 있겠군요!</color>","JPN":"<color=#ffd34c>間もなく大騒ぎになるでしょうが、少なくとも今だけはこの森の静けさを楽しみながらお話できますね！</color>","ENG":"<color=#ffd34c>Soon, that'll change, but let's try to enjoy the quietness of this forest while we can, shall we?</color>","TWN":"<color=#ffd34c>雖然很快就會掀起一片腥風血雨，但現在就好好享受這暴風雨前的寧靜吧！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CLAP_02"},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…진짜 TV잖아?","JPN":"本当にテレビがある……","ENG":"...There really is a TV.","TWN":"…真的是電視？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"헤헤, 거 봐! 내 말이 맞지?","JPN":"へへ、ほら！　俺の勘違いじゃないだろ？","ENG":"Heh heh. See, I told you!","TWN":"哈哈，你看，我沒說錯吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"하지만 어떻게 이런 고심도에서 TV 같은 게 멀쩡히 작동할 수 있는 거지?","JPN":"でもどうしてこんな高深度でテレビが普通に映ってるの？","ENG":"But how is it still working in the hyperdepths?","TWN":"在這種高深度的地方，電視怎麼可能還可以正常運作呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"앗?! 그러고 보니?","JPN":"あっ！？　確かに！","ENG":"Ah, you're right!","TWN":"對欸，說的也是！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그야 간단하죠! 제 쇼는 전기 플러그나 전파의 부재 따위로 멈출 수 없으니까요!</color>","JPN":"<color=#ffd34c>それは簡単なことです！　私のショーは電源プラグや電波の有無なんてものに影響されないのですから！</color>","ENG":"<color=#ffd34c>Easy! Nothing can stop my show, even the absence of electricity or electromagnetic waves!</color>","TWN":"<color=#ffd34c>這道理很簡單！就是我的節目不會因為沒有插頭，或沒電而無法播出！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대답하는 TV라니… 신기해.","JPN":"へ、返事をするテレビがあるなんて……不思議だね。","ENG":"A-a talking TV... Holy cow!","TWN":"電視機在說話…世界奇觀。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저어, 혹시 침식체이신가요?","JPN":"あの、もしかして侵食体ですか？","ENG":"Erm, are you a C.O. by chance?","TWN":"請問，你是侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그럴 수도 있고, 아닐 수도 있죠!</color>","JPN":"<color=#ffd34c>そうかもしれませんし、それでないかもしれませんね！</color>","ENG":"<color=#ffd34c>Maybe. Maybe not.</color>","TWN":"<color=#ffd34c>可能是，也可能不是！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>하지만 지금 이 쇼에서 주목해야 할 주인공은 제가 아니라 바로 여러분입니다!</color>","JPN":"<color=#ffd34c>しかし今このショーで注目すべき主人公は私ではなく、皆様です！</color>","ENG":"<color=#ffd34c>But I'm not a special guest of this show—you are!</color>","TWN":"<color=#ffd34c>不過容我提醒一下，這個節目的主角不是我，而是各位！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 말은 당신이 우릴 이곳으로 불러들인 것처럼 들리는데요?","JPN":"その言葉だと、あなたが私たちをここに呼び出した、というように聞こえますが？","ENG":"To me, that sounds like you've dragged us here. Have you?","TWN":"聽起來，意思是你刻意把我們帶到這裡來的嗎？"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>아뇨! 제 쇼는 리얼리티를 최고로 추구합니다. 억지스러운 연출은 감상을 망칠 뿐이죠.</color>","JPN":"<color=#ffd34c>いいえ！　私のショーはリアリティが大事です。わざとらしい演出は感情移入を阻害するだけです。</color>","ENG":"<color=#ffd34c>Absolutely not! My show is all about realism. Artificial intervention only disrupts its integrity.</color>","TWN":"<color=#ffd34c>當然不是！我的節目最講究的就是真實性！Set好的東西根本沒看頭！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L35_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>뭐, 재미도 감동도 없는 최악의 전개를 피하기 위해 약간의 충고를 드릴 수는 있겠네요.</color>","JPN":"<color=#ffd34c>まあ、面白みも感動もない最悪の展開を避けるために、少しだけアドバイスさせていただくことはできそうですね。</color>","ENG":"<color=#ffd34c>But I guess I could give you a piece of advice, to prevent a boring or disastrous conclusion.</color>","TWN":"<color=#ffd34c>不過主角一開始就死光，觀眾也不會買單，所以我是可以給你們一些忠告。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>가령, 지금처럼 당신의 동료를 몰래 잡아먹으려는 침식체에 대해 알려준다 거나 말입니다.</color>","JPN":"<color=#ffd34c>例えば、今まさにあなたの仲間をこっそり餌食にしようとする侵食体について教えてあげるとか、です。</color>","ENG":"<color=#ffd34c>For instance, right now, a C.O. is trying to sneak up on your teammate, with its mouth gaping open.</color>","TWN":"<color=#ffd34c>譬如說，現在有侵蝕體想要突襲你的夥伴，之類的。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"…뭐?","JPN":"……は？","ENG":"What?","TWN":"…什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"유진아! 위험해!","JPN":"シロコ！　危ない！","ENG":"Eujin! Watch out!","TWN":"劉珍，危險！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"크윽! 하마터면 당할 뻔했어.","JPN":"くっ！　危ないところだった……","ENG":"Geez, that was close.","TWN":"唔！差點GG！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대체 이 꿈틀거리는 덩어리는 뭐야? 언제 이런 게 나타난 거지?","JPN":"いったいこのグニャグニャした塊はなんだ？　いつどこからこんなのが出てきやがったんだ？","ENG":"What the hell is this squirmy mess? Where the hell did it come from?","TWN":"那一團東西到底是什麼？什麼時候冒出來的？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"다, 다시 일어나려 하고 있는 것 같아. 어쩌지?","JPN":"ま、また立ち上がろうとしてる。どうしよう？","ENG":"I-I think it's coming to life again. What should we do?","TWN":"它…還在動欸，怎麼辦？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저게… 정말로 우리가 알던 침식체라고?","JPN":"あれは……本当に私たちが知っている侵食体なの？","ENG":"Seriously, is that even a C.O.?","TWN":"那個…真的是我們認識的侵蝕體嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>이런! 버려진 영지의 낡은 허물들이 당신들을 발견해버린 것 같군요!</color>","JPN":"<color=#ffd34c>おっと！　捨てられた領地の古い抜け殻があなた方を見つけてしまったようですね！</color>","ENG":"<color=#ffd34c>Uh-oh, the old refuse of the abandoned estate has found you.</color>","TWN":"<color=#ffd34c>哎呀！荒廢領地的廢棄物似乎發現你們囉！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>과연, 우리의 주인공들은 무사히 악몽의 단편으로부터 벗어날 수 있을 것인가!</color>","JPN":"<color=#ffd34c>果たして、主人公たちは無事に悪夢の断片から逃れることができるのか！</color>","ENG":"<color=#ffd34c>Alright, let's see if our guests can safely escape from these fragments of the nightmare!</color>","TWN":"<color=#ffd34c>揪竟，主角們能否從這場惡夢中醒來呢？讓我們繼續看下去！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"쳇, 대체 무슨 장난질이야?! 수작부리지 말고 당장 여기서 빠져나가게 해달라고!","JPN":"ちっ、なんの真似だ！？　イタズラは程々にして今すぐここから出せ！","ENG":"Bah, what kind of game is this? Stop messing with us. Let us get out of here now!","TWN":"它以為現在是在演藍色蛛蛛網膩！少在那邊耍嘴皮，快點讓我們離開這裡！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>이곳은 옛 호수의 허물. 영겁과 함께 말라비틀어진 악몽의 흔적.</color>","JPN":"<color=#ffd34c>ここは古き湖の抜け殻。永劫の昔に枯れてしまった悪夢の跡。</color>","ENG":"<color=#ffd34c>This is the discharge from the old Lake, a desiccated trace of the never-ending nightmare.</color>","TWN":"<color=#ffd34c>這裡以前是湖水，隨著漫長歲月而乾涸的惡夢痕跡。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>진정한 호수의 악몽에 비하면 티끌과도 같은 위협일 뿐이지만, 파훼법은 같습니다!</color>","JPN":"<color=#ffd34c>真の湖の悪夢に比べれば塵のような脅威にすぎませんが、対処法は同じです！</color>","ENG":"<color=#ffd34c>Compared to the original Lake, this one's only as threatening as a speck of dust, but it also requires the same solution.</color>","TWN":"<color=#ffd34c>雖然比起真正的湖水惡夢是小巫見大巫，但處理的方法是一樣的！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>예나 지금이나 꿈에서 깨려면 충격요법이 제일이라는 거죠!</color>","JPN":"<color=#ffd34c>今も昔も、夢から覚めるにはショック療法が一番ということですね！</color>","ENG":"<color=#ffd34c>Shock therapy! It's the time-tested method to wake someone up from terrible dreams!</color>","TWN":"<color=#ffd34c>無論過去或現在，受到刺激是從夢裡醒來的最佳方法！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알겠어요. 뭐가 나타나든, 이 괴상한 것들을 닥치는 대로 해치우면 빠져 나갈 길이 열린다는 거죠?","JPN":"わかりました。現れるのが何者であれ、この奇妙なモノを片っ端から片付ければ出口が開かれるということですよね？","ENG":"I get it. We have to cut a path through these grotesque-looking things, no matter what. Right?","TWN":"我知道了，不管是什麼，來幾個就殺幾個，這樣應該就可以離開這裡吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장, 정말로 저 정체도 모를 목소리가 시키는 대로 할 셈이야?","JPN":"隊長、本当にあの得体の知れない声のとおりにするつもり？","ENG":"Cap, are you really going to do as that mysterious voice says?","TWN":"隊長，你真的要照著那個來路不明的東西所說的做嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"괜찮아, 린.","JPN":"大丈夫よ、リン。","ENG":"Don't worry, Lin.","TWN":"沒問題的，曉琳。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"함께 싸워서 난관을 해쳐 나가는 건, 우리가 원래부터 가장 잘하는 거잖아?","JPN":"一緒に戦って難関を切り抜けるのは、私たちが一番得意とすることでしょ？","ENG":"It's what we do best, fighting and overcoming challenges together.","TWN":"關關難過關關過，不就是我們從以前到現在最擅長的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장이 그렇다면, 나도 상관없어.","JPN":"隊長が決めたなら、私もついていく。","ENG":"If you want to do it, then I want to do it.","TWN":"隊長怎麼說我怎麼做。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"흥! 이름도 모르는 녀석 말을 듣는 게 걸리긴 하지만, 방법은 간단해서 좋네.","JPN":"ふん！　名前も知らない奴の指図を受けるのは気に食わないが、解決方法はシンプルでいいな。","ENG":"Sheesh, I don't want to listen to a complete stranger, but I like that his solution is simple.","TWN":"哼！雖然覺得那個東西說的話肯定有詐，但至少方法是簡單的！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"나, 나도 힘내서 열심히 싸워볼게!","JPN":"わ、私も頑張って戦うよ！","ENG":"I-I'll do my best to fight, too!","TWN":"我…我也會一起努力作戰！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>하하! 이전까지의 낙오자들과 다르게 담합력이 좋네요! 훌륭합니다!</color>","JPN":"<color=#ffd34c>ハハハ！　これまでの脱落者たちと違い、強い団結力ですね！　素晴らしい！</color>","ENG":"<color=#ffd34c>Hah hah. Unlike the others who tried this and failed, you have a strong bond. I like that!</color>","TWN":"<color=#ffd34c>哈哈，你們是我目前為止看過最團結的呢！非常好！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그럼! 쇼를 시작하도록 하죠!</color>","JPN":"<color=#ffd34c>では！　ショーを始めるとしましょう！</color>","ENG":"<color=#ffd34c>Now, let's start the show!</color>","TWN":"<color=#ffd34c>那麼！好戲上場囉！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};